// IsInteractive returns true when the CLI should use interactive features.
// Requires both stdin and stdout to be a TTY, --no-interactive must not be set,
// and agent mode must not be active. Agent mode (auto-detected from AI coding
// agent env vars or --agent-mode flag) implies non-interactive operation even
// when running in a real terminal.
func IsInteractive(cmd *cobra.Command) bool {
	if noInteractive, _ := flagutil.GetBoolFlag(cmd, "no-interactive"); noInteractive {
		return false
	}
	if output.IsAgentMode() {
		return false
	}
	return term.IsTerminal(int(os.Stdin.Fd())) && term.IsTerminal(int(os.Stdout.Fd()))
}

// ShouldPrompt returns true when the command should auto-prompt for missing
// required flags. This is true when IsInteractive is true and at least one
// required flag has no value from any resolution source (flag, env, config).
func ShouldPrompt(cmd *cobra.Command, meta []flagutil.FlagMeta) bool {
	if !IsInteractive(cmd) {
		return false
	}
	for _, m := range meta {
		if !m.Required {
			continue
		}
		if isValueResolved(cmd, m) {
			continue
		}
		return true
	}
	return false
}

// isValueResolved checks whether a flag's value can be satisfied without
// user input, by checking the same sources BuildRequest uses:
// 1. Explicit flag (--flag=value)
// 2. Environment variable (if FlagMeta.EnvVar is set)
// 3. Config file (if FlagMeta.ConfigKey is set)
func isValueResolved(cmd *cobra.Command, m flagutil.FlagMeta) bool {
	if f := cmd.Flags().Lookup(m.FlagName); f != nil && f.Changed {
		return true
	}
	if m.EnvVar != "" {
		if _, ok := os.LookupEnv(m.EnvVar); ok {
			return true
		}
	}
	if m.ConfigKey != "" {
		if v := config.GetConfigValue(m.ConfigKey); v != "" {
			return true
		}
	}
	return false
}

