// printCommandHeader prints the command documentation header to the terminal
// before the form starts. This avoids huh.Note rendering issues.
func printCommandHeader(cmd *cobra.Command, totalRequired, totalOptional int) {
	accent := lipgloss.Color("#38BDF8")
	dimmed := lipgloss.Color("#64748B")

	titleStyle := lipgloss.NewStyle().Foreground(accent).Bold(true)
	descStyle := lipgloss.NewStyle().Foreground(dimmed).Italic(true)
	infoStyle := lipgloss.NewStyle().Foreground(dimmed)

	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, titleStyle.Render(cmd.CommandPath()))

	if cmd.Long != "" {
		longLines := strings.SplitN(cmd.Long, "\n", 2)
		fmt.Fprintln(os.Stderr, descStyle.Render(longLines[0]))
	} else if cmd.Short != "" {
		fmt.Fprintln(os.Stderr, descStyle.Render(cmd.Short))
	}

	var parts []string
	if totalRequired > 0 {
		parts = append(parts, fmt.Sprintf("%d required", totalRequired))
	}
	if totalOptional > 0 {
		parts = append(parts, fmt.Sprintf("%d optional", totalOptional))
	}
	if len(parts) > 0 {
		fmt.Fprintln(os.Stderr, infoStyle.Render(strings.Join(parts, ", ")+" field(s)"))
	}
	fmt.Fprintln(os.Stderr)
}

