// buildStringInput creates a simple huh text input for string-like fields.
func buildStringInput(m flagutil.FlagMeta, title, desc string) (huh.Field, flagBinding) {
	val := ""
	field := huh.NewInput().
		Title(title).
		Description(desc).
		Placeholder(m.DefaultStr).
		Value(&val)
	if m.Required {
		field = field.Validate(func(s string) error {
			if strings.TrimSpace(s) == "" {
				return fmt.Errorf("required")
			}
			return nil
		})
	}
	return field, flagBinding{flagName: m.FlagName, kind: m.Kind, strVal: &val, optional: m.Optional}
}

// flagDisplayName returns a human-friendly title for a form field.
// Converts kebab-case flag names to Title Case and appends (required) if needed.
// For nested flags like "request-body.number-value", uses only the last segment.
func flagDisplayName(m flagutil.FlagMeta) string {
	name := m.FlagName
	// Use the last segment for nested flags
	if idx := strings.LastIndex(name, "."); idx >= 0 {
		name = name[idx+1:]
	}
	// Convert kebab-case to Title Case
	parts := strings.Split(name, "-")
	for i, p := range parts {
		if len(p) > 0 {
			parts[i] = strings.ToUpper(p[:1]) + p[1:]
		}
	}
	title := strings.Join(parts, " ")
	if m.Required {
		title += " (required)"
	}
	return title
}

// flagDescription returns a description combining the schema description
// and the corresponding CLI flag name for reference.
func flagDescription(m flagutil.FlagMeta) string {
	parts := []string{}
	if m.Description != "" {
		parts = append(parts, m.Description)
	}
	parts = append(parts, "--"+m.FlagName)
	return strings.Join(parts, " · ")
}

// PromptForBodyJSON prompts for a JSON body when the operation uses a single
// body flag (non-metadata-driven). Used for complex request bodies that aren't
// expanded into individual flags.
func PromptForBodyJSON(cmd *cobra.Command, flagName, description string) error {
	if f := cmd.Flags().Lookup(flagName); f != nil && f.Changed {
		return nil // already set
	}

	val := ""
	field := huh.NewText().
		Title("Request Body").
		Description(description + " (JSON)").
		Value(&val).
		Validate(func(s string) error {
			if strings.TrimSpace(s) == "" {
				return fmt.Errorf("required")
			}
			return nil
		})

	form := huh.NewForm(huh.NewGroup(field)).
		WithWidth(formWidth()).
		WithTheme(formTheme()).
		WithShowHelp(false)

	if err := form.Run(); err != nil {
		return fmt.Errorf("interactive prompt: %w", err)
	}

	if val != "" {
		return cmd.Flags().Set(flagName, val)
	}
	return nil
}

// ShouldPromptForBody returns true when the body flag is unset and we're in
// interactive mode. Used for non-metadata operations with a single body flag.
func ShouldPromptForBody(cmd *cobra.Command, flagName string) bool {
	if !IsInteractive(cmd) {
		return false
	}
	if f := cmd.Flags().Lookup(flagName); f != nil && f.Changed {
		return false
	}
	return true
}
